VALUES
  ('disabled-57f41407-moex-00066', 'disabled-57f41407', 'disabled-57f41407-moex-114-1611a566', 'sub-disabled-57f41407-02', NULL, 'single_choice', '關於撤回上訴，下列敘述何者正確？', '["上訴人應得被上訴人同意，始得將上訴撤回", "上訴人撤回上訴後（對造未上訴），於上訴不變期間內，得再為上訴", "上訴人撤回上訴後，可就同一事件，再另行起訴", "原告於被告上訴第二審法院中，撤回起訴，上訴人得於3個月內請求退 還第二審上訴費三分之二"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:34+00:00", "source_pdf_sha1": "f8c4261c4045", "answer_pdf_sha1": "535045d9caaa", "source_family": "moex-gov-tw", "moex": {"exam_code": "114040", "c": "504", "s": "0410", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "民事訴訟法大意與刑事訴訟法大意", "year": "114", "exam_name": "114年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 16, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "錄事"}'::jsonb, NULL),
  ('disabled-57f41407-moex-00067', 'disabled-57f41407', 'disabled-57f41407-moex-114-1611a566', 'sub-disabled-57f41407-02', NULL, 'single_choice', '關於附帶上訴，下列敘述何者正確？', '["被上訴人提起附帶上訴，均不必繳納第二審裁判費", "被上訴人於上訴期間內提起附帶上訴，如對造當事人之上訴經認為不合 法而遭駁回，則附帶上訴失其效力", "當事人於第一審判決宣示後捨棄上訴權，如他造當事人提起上訴，仍得 提起附帶上訴", "被上訴人於第二審言詞辯論終結前，均得提起附帶上訴"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:34+00:00", "source_pdf_sha1": "f8c4261c4045", "answer_pdf_sha1": "535045d9caaa", "source_family": "moex-gov-tw", "moex": {"exam_code": "114040", "c": "504", "s": "0410", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "民事訴訟法大意與刑事訴訟法大意", "year": "114", "exam_name": "114年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 17, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "錄事"}'::jsonb, NULL),
  ('disabled-57f41407-moex-00068', 'disabled-57f41407', 'disabled-57f41407-moex-114-1611a566', 'sub-disabled-57f41407-02', NULL, 'single_choice', '下列何者非屬第三審法院許可上訴之事由？', '["從事法之續造", "事實認定錯誤", "確保裁判之一致性", "所涉及之法律見解具有原則上重要性"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:34+00:00", "source_pdf_sha1": "f8c4261c4045", "answer_pdf_sha1": "535045d9caaa", "source_family": "moex-gov-tw", "moex": {"exam_code": "114040", "c": "504", "s": "0410", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "民事訴訟法大意與刑事訴訟法大意", "year": "114", "exam_name": "114年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 18, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "錄事"}'::jsonb, NULL),
  ('disabled-57f41407-moex-00069', 'disabled-57f41407', 'disabled-57f41407-moex-114-1611a566', 'sub-disabled-57f41407-02', NULL, 'single_choice', '甲起訴請求乙清償借款，訴訟程序進行中乙死亡，甲及乙之繼承人丙均未 聲明承受訴訟，法院乃裁定丙為乙之承受訴訟人以續行訴訟（下稱系爭裁 定），下列敘述何者正確？', '["甲對於系爭裁定，得提起抗告", "丙對於系爭裁定，不得聲明不服", "第三人丁主張其為乙之債權人，為利害關係人，得對於系爭裁定提起抗告", "第三人戊主張其為丙之債權人，為利害關係人，得對於系爭裁定提起抗告"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:34+00:00", "source_pdf_sha1": "f8c4261c4045", "answer_pdf_sha1": "535045d9caaa", "source_family": "moex-gov-tw", "moex": {"exam_code": "114040", "c": "504", "s": "0410", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "民事訴訟法大意與刑事訴訟法大意", "year": "114", "exam_name": "114年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 19, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "錄事"}'::jsonb, NULL),
  ('disabled-57f41407-moex-00070', 'disabled-57f41407', 'disabled-57f41407-moex-114-1611a566', 'sub-disabled-57f41407-02', NULL, 'single_choice', '關於再審理由，下列敘述何者正確？', '["由未參與言詞辯論之法官作成判決，不構成再審理由", "關於訴訟未經合法代理之再審理由，限於未經合法代理一方之當事人得 提起再審之訴，他造當事人不得以此為由提起再審之訴", "當事人於判決確定後發現未經斟酌之證物，而該證物屬該訴訟之事實審 言詞辯論終結前尚未存在之證物，得作為再審理由", "得上訴第三審之事件，如有足影響於判決之重要證物漏未斟酌，得作為 再審理由"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:34+00:00", "source_pdf_sha1": "f8c4261c4045", "answer_pdf_sha1": "535045d9caaa", "source_family": "moex-gov-tw", "moex": {"exam_code": "114040", "c": "504", "s": "0410", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "民事訴訟法大意與刑事訴訟法大意", "year": "114", "exam_name": "114年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 20, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "錄事"}'::jsonb, NULL),
  ('disabled-57f41407-moex-00071', 'disabled-57f41407', 'disabled-57f41407-moex-114-1611a566', 'sub-disabled-57f41407-02', NULL, 'single_choice', '關於第三人撤銷訴訟之效力，下列敘述何者錯誤？', '["若原確定判決已開始強制執行，於起訴後原則上仍不停止執行", "法院於判決前，得定相當並確實之擔保，於聲明範圍內以裁定停止原確 定判決對第三人不利部分之執行", "於判決前，即使當事人依法院之命提供確實之擔保，法院仍不得停止原 確定判決對第三人不利部分之形成力", "法院之判決，對於第三人以善意取得之權利，不生影響"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:34+00:00", "source_pdf_sha1": "f8c4261c4045", "answer_pdf_sha1": "535045d9caaa", "source_family": "moex-gov-tw", "moex": {"exam_code": "114040", "c": "504", "s": "0410", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "民事訴訟法大意與刑事訴訟法大意", "year": "114", "exam_name": "114年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 21, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "錄事"}'::jsonb, NULL),
  ('disabled-57f41407-moex-00072', 'disabled-57f41407', 'disabled-57f41407-moex-114-1611a566', 'sub-disabled-57f41407-02', NULL, 'single_choice', '關於督促程序之管轄，下列敘述何者錯誤？', '["依督促程序聲請法院核發支付命令，屬專屬管轄", "債務人設有事務所或營業所者，以因關於其事務所或營業所之業務發生 債權債務關係涉訟者為限，得由該事務所或營業所所在地之法院管轄", "債務人住所地跨連數法院管轄區域內，依民事訴訟法第 21 條規定，各 該法院俱有管轄權", "法院對於支付命令之聲請，認無管轄權者，應依職權或依債權人之聲請， 以裁定移送於管轄法院"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:34+00:00", "source_pdf_sha1": "f8c4261c4045", "answer_pdf_sha1": "535045d9caaa", "source_family": "moex-gov-tw", "moex": {"exam_code": "114040", "c": "504", "s": "0410", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "民事訴訟法大意與刑事訴訟法大意", "year": "114", "exam_name": "114年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 22, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "錄事"}'::jsonb, NULL),
  ('disabled-57f41407-moex-00073', 'disabled-57f41407', 'disabled-57f41407-moex-114-1611a566', 'sub-disabled-57f41407-02', NULL, 'single_choice', '關於宣告證券無效之公示催告及除權判決程序，下列敘述何者正確？', '["無記名證券或空白背書之指示證券以外之證券，應由最後之持有人為公 示催告之聲請", "持有證券人經申報權利並提出證券者，法院無須通知聲請人，並酌定期 間使其閱覽證券，即應終結公示催告程序", "申報權利之期間，自公示催告之公告開始公告於法院網站之日起、最後 登載公報、新聞紙之日起，應有3個月以上9個月以下", "對於除權判決所附之限制或保留，不得抗告"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:34+00:00", "source_pdf_sha1": "f8c4261c4045", "answer_pdf_sha1": "535045d9caaa", "source_family": "moex-gov-tw", "moex": {"exam_code": "114040", "c": "504", "s": "0410", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "民事訴訟法大意與刑事訴訟法大意", "year": "114", "exam_name": "114年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 23, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "錄事"}'::jsonb, NULL),
  ('disabled-57f41407-moex-00074', 'disabled-57f41407', 'disabled-57f41407-moex-114-1611a566', 'sub-disabled-57f41407-02', NULL, 'single_choice', '下列何種情形係屬於專屬管轄事件？', '["本於票據有所請求而涉訟", "因共有土地之分割而涉訟", "因海難救助而涉訟", "因船舶碰撞請求損害賠償而涉訟"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:34+00:00", "source_pdf_sha1": "f8c4261c4045", "answer_pdf_sha1": "535045d9caaa", "source_family": "moex-gov-tw", "moex": {"exam_code": "114040", "c": "504", "s": "0410", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "民事訴訟法大意與刑事訴訟法大意", "year": "114", "exam_name": "114年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 24, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "錄事"}'::jsonb, NULL),
  ('disabled-57f41407-moex-00075', 'disabled-57f41407', 'disabled-57f41407-moex-114-1611a566', 'sub-disabled-57f41407-02', NULL, 'single_choice', '下列何者不屬於民事訴訟程序當然停止之事由？', '["被選定為訴訟當事人之人全體喪失其資格", "已委任訴訟代理人之當事人死亡", "法院因天災或其他不可避之事故不能執行職務", "受託人之信託任務終了 乙、刑事訴訟法部分"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:34+00:00", "source_pdf_sha1": "f8c4261c4045", "answer_pdf_sha1": "535045d9caaa", "source_family": "moex-gov-tw", "moex": {"exam_code": "114040", "c": "504", "s": "0410", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "民事訴訟法大意與刑事訴訟法大意", "year": "114", "exam_name": "114年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 25, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "錄事"}'::jsonb, NULL)
